  1→import { useState, useEffect, type FormEvent } from "react";
  2→import {
  3→  GitBranch,
  4→  BookOpen,
  5→  ChevronRight,
  6→  ChevronDown,
  7→  FolderGit2,
  8→  FolderPlus,
  9→  Loader2,
 10→  PanelLeftClose,
 11→  PanelLeftOpen,
 12→  Plus,
 13→  RefreshCw,
 14→  Trash2,
 15→  X,
 16→} from "lucide-react";
 17→import { open } from "@tauri-apps/plugin-dialog";
 18→import type { Tab } from "../../App";
 19→import type { BranchInfo, RepoInfo, WorktreeInfo } from "../../lib/ipc";
 20→import {
 21→  useCreateWorktreeMutation,
 22→  useDeleteBranchMutation,
 23→  useDeleteWorktreeMutation,
 24→  useRegisterRepoMutation,
 25→  useReposQuery,
 26→  useUnregisterRepoMutation,
 27→} from "../../hooks/use-tauri-query";
 28→import { canDeletePlainBranch } from "./branch-delete-state.ts";
 29→import { buildCreateWorktreeDraft } from "./worktree-dialog-state.ts";
 30→import { isRepoRefreshing } from "./refresh-state";
 31→import { deriveSuggestedWorktreePath } from "./worktree-paths.ts";
 32→
 33→interface SidebarProps {
 34→  activeTab: Tab;
 35→  width: number;
 36→  onBranchSelect: (branch: BranchInfo, repoPath: string) => void;
 37→  onBranchDeleted: (branchName: string, repoPath: string) => void;
 38→  onWorktreeDeleted: (worktreePath: string) => void;
 39→  onWorktreeSelect: (wt: WorktreeInfo) => void;
 40→  onResizeStart: (event: React.MouseEvent<HTMLDivElement>) => void;
 41→}
 42→
 43→interface CreateWorktreeDialogState {
 44→  repoPath: string;
 45→  mode: "existing" | "new";
 46→  branchName: string;
 47→  targetPath: string;
 48→  pathEdited: boolean;
 49→  error: string | null;
 50→}
 51→
 52→interface DeleteWorktreeDialogState {
 53→  repoPath: string;
 54→  worktree: WorktreeInfo;
 55→  error: string | null;
 56→  forceAvailable: boolean;
 57→}
 58→
 59→interface DeleteBranchDialogState {
 60→  repoPath: string;
 61→  branchName: string;
 62→  error: string | null;
 63→}
 64→
 65→function getErrorMessage(error: unknown): string {
 66→  return error instanceof Error ? error.message : String(error);
 67→}
 68→
 69→function getAvailableExistingBranches(repo: RepoInfo): string[] {
 70→  const worktreeBranches = new Set(repo.worktrees.map((worktree) => worktree.branch));
 71→  return repo.branches
 72→    .filter((branch) => !branch.is_head && !worktreeBranches.has(branch.name))
 73→    .map((branch) => branch.name);
 74→}
 75→
 76→export function Sidebar({
 77→  activeTab,
 78→  width,
 79→  onBranchSelect,
 80→  onBranchDeleted,
 81→  onWorktreeDeleted,
 82→  onWorktreeSelect,
 83→  onResizeStart,
 84→}: SidebarProps) {
 85→  const { data: realRepos, isLoading, error, refetch } = useReposQuery();
 86→  const registerMutation = useRegisterRepoMutation();
 87→  const unregisterMutation = useUnregisterRepoMutation();
 88→  const createWorktreeMutation = useCreateWorktreeMutation();
 89→  const deleteBranchMutation = useDeleteBranchMutation();
 90→  const deleteWorktreeMutation = useDeleteWorktreeMutation();
 91→
 92→  const repos = realRepos ?? [];
 93→
 94→  const [expandedRepos, setExpandedRepos] = useState<Set<string>>(new Set());
 95→  const [repoListCollapsed, setRepoListCollapsed] = useState(false);
 96→  const [collapsed, setCollapsed] = useState(false);
 97→  const [sidebarError, setSidebarError] = useState<string | null>(null);
 98→  const [refreshingRepoPath, setRefreshingRepoPath] = useState<string | null>(null);
 99→  const [createDialog, setCreateDialog] = useState<CreateWorktreeDialogState | null>(null);
100→  const [deleteBranchDialog, setDeleteBranchDialog] = useState<DeleteBranchDialogState | null>(null);
101→  const [deleteDialog, setDeleteDialog] = useState<DeleteWorktreeDialogState | null>(null);
102→
103→  const createRepo = createDialog
104→    ? repos.find((repo) => repo.path === createDialog.repoPath) ?? null
105→    : null;
106→  const createAvailableBranches = createRepo ? getAvailableExistingBranches(createRepo) : [];
107→  const worktreeBranches = new Set(
108→    repos.flatMap((repo) => repo.worktrees.map((worktree) => worktree.branch))
109→  );
110→
111→  async function handleAddRepo() {
112→    setSidebarError(null);
113→    const selected = await open({ directory: true, multiple: false });
114→    if (!selected) return;
115→    registerMutation.mutate(selected, {
116→      onError: (mutationError) => {
117→        setSidebarError(getErrorMessage(mutationError));
118→      },
119→    });
120→  }
121→
122→  async function handleRefreshRepo(repoPath: string) {
123→    setSidebarError(null);
124→    setRefreshingRepoPath(repoPath);
125→
126→    try {
127→      const result = await refetch();
128→      if (result.error) {
129→        setSidebarError(getErrorMessage(result.error));
130→      }
131→    } catch (refreshError) {
132→      setSidebarError(getErrorMessage(refreshError));
133→    } finally {
134→      setRefreshingRepoPath(null);
135→    }
136→  }
137→
138→  function handleOpenCreateDialog(repo: RepoInfo) {
139→    const draft = buildCreateWorktreeDraft(repo);
140→    setSidebarError(null);
141→    setCreateDialog({
142→      repoPath: repo.path,
143→      mode: draft.mode,
144→      branchName: draft.branchName,
145→      targetPath: draft.targetPath,
146→      pathEdited: false,
147→      error: null,
148→    });
149→  }
150→
151→  function updateCreateDialog(
152→    updater: (current: CreateWorktreeDialogState) => CreateWorktreeDialogState
153→  ) {
154→    setCreateDialog((current) => (current ? updater(current) : current));
155→  }
156→
157→  function handleCreateModeChange(mode: "existing" | "new") {
158→    updateCreateDialog((current) => {
159→      if (!createRepo) return current;
160→      const nextBranchName =
161→        mode === "existing"
162→          ? createAvailableBranches[0] ?? ""
163→          : current.mode === "new"
164→            ? current.branchName
165→            : "";
166→      const nextTargetPath = current.pathEdited
167→        ? current.targetPath
168→        : deriveSuggestedWorktreePath(createRepo.path, nextBranchName);
169→
170→      return {
171→        ...current,
172→        mode,
173→        branchName: nextBranchName,
174→        targetPath: nextTargetPath,
175→        error: null,
176→      };
177→    });
178→  }
179→
180→  function handleCreateBranchNameChange(branchName: string) {
181→    updateCreateDialog((current) => ({
182→      ...current,
183→      branchName,
184→      targetPath: current.pathEdited
185→        ? current.targetPath
186→        : deriveSuggestedWorktreePath(current.repoPath, branchName),
187→      error: null,
188→    }));
189→  }
190→
191→  async function handleCreateSubmit(event: FormEvent<HTMLFormElement>) {
192→    event.preventDefault();
193→    if (!createDialog) return;
194→
195→    setSidebarError(null);
196→    updateCreateDialog((current) => ({ ...current, error: null }));
197→
198→    try {
199→      await createWorktreeMutation.mutateAsync({
200→        repoPath: createDialog.repoPath,
201→        options: {
202→          mode: createDialog.mode,
203→          branchName: createDialog.branchName,
204→          targetPath: createDialog.targetPath,
205→        },
206→      });
207→      setCreateDialog(null);
208→    } catch (mutationError) {
209→      const message = getErrorMessage(mutationError);
210→      setSidebarError(message);
211→      updateCreateDialog((current) => ({ ...current, error: message }));
212→    }
213→  }
214→
215→  function handleOpenDeleteDialog(repoPath: string, worktree: WorktreeInfo) {
216→    setSidebarError(null);
217→    setDeleteDialog({
218→      repoPath,
219→      worktree,
220→      error: null,
221→      forceAvailable: false,
222→    });
223→  }
224→
225→  function handleOpenDeleteBranchDialog(repoPath: string, branchName: string) {
226→    setSidebarError(null);
227→    setDeleteBranchDialog({
228→      repoPath,
229→      branchName,
230→      error: null,
231→    });
232→  }
233→
234→  async function handleDeleteBranchSubmit() {
235→    if (!deleteBranchDialog) return;
236→
237→    setSidebarError(null);
238→    setDeleteBranchDialog((current) => (current ? { ...current, error: null } : current));
239→
240→    try {
241→      await deleteBranchMutation.mutateAsync({
242→        repoPath: deleteBranchDialog.repoPath,
243→        branchName: deleteBranchDialog.branchName,
244→      });
245→      onBranchDeleted(deleteBranchDialog.branchName, deleteBranchDialog.repoPath);
246→      setDeleteBranchDialog(null);
247→    } catch (mutationError) {
248→      const message = getErrorMessage(mutationError);
249→      setSidebarError(message);
250→      setDeleteBranchDialog((current) =>
251→        current ? { ...current, error: message } : current
252→      );
253→    }
254→  }
255→
256→  async function handleDeleteSubmit(force: boolean) {
257→    if (!deleteDialog) return;
258→
259→    setSidebarError(null);
260→    setDeleteDialog((current) => (current ? { ...current, error: null } : current));
261→
262→    try {
263→      await deleteWorktreeMutation.mutateAsync({
264→        repoPath: deleteDialog.repoPath,
265→        options: {
266→          worktreePath: deleteDialog.worktree.path,
267→          branchName: deleteDialog.worktree.branch,
268→          force,
269→        },
270→      });
271→      onWorktreeDeleted(deleteDialog.worktree.path);
272→      setDeleteDialog(null);
273→    } catch (mutationError) {
274→      const message = getErrorMessage(mutationError);
275→      setSidebarError(message);
276→      setDeleteDialog((current) =>
277→        current
278→          ? {
279→              ...current,
280→              error: message,
281→              forceAvailable: current.forceAvailable || !force,
282→            }
283→          : current
284→      );
285→    }
286→  }
287→
288→  useEffect(() => {
289→    setExpandedRepos(new Set(repos.map((repo) => repo.path)));
290→  }, [repos]);
291→
292→  function toggleRepo(path: string) {
293→    setExpandedRepos((prev) => {
294→      const next = new Set(prev);
295→      if (next.has(path)) next.delete(path);
296→      else next.add(path);
297→      return next;
298→    });
299→  }
300→
301→  const createSubmitDisabled =
302→    createWorktreeMutation.isPending ||
303→    !createDialog ||
304→    !createDialog.branchName.trim() ||
305→    !createDialog.targetPath.trim() ||
306→    (createDialog.mode === "existing" && createAvailableBranches.length === 0);
307→
308→  if (collapsed) {
309→    return (
310→      <>
311→        <div className="flex w-[48px] shrink-0 flex-col items-center border-r border-border bg-bg-raised py-3">
312→          <button
313→            onClick={() => setCollapsed(false)}
314→            className="mb-4 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
315→            title="Expand sidebar"
316→          >
317→            <PanelLeftOpen size={16} />
318→          </button>
319→          {repos.map((repo) => (
320→            <button
321→              key={repo.path}
322→              className="mb-1 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
323→              title={repo.name}
324→            >
325→              <BookOpen size={14} />
326→            </button>
327→          ))}
328→        </div>
329→        {createDialog && createRepo && (
330→          <div className="fixed inset-0 z-20 flex items-center justify-center bg-black/50 p-4">
331→            <form
332→              onSubmit={handleCreateSubmit}
333→              className="w-full max-w-md rounded-lg border border-border bg-bg-overlay shadow-2xl"
334→            >
335→              <div className="flex items-center border-b border-border-subtle px-4 py-3">
336→                <div className="flex-1">
337→                  <h3 className="text-sm font-semibold text-fg">Create worktree</h3>
338→                  <p className="mt-1 text-xs text-fg-muted">{createRepo.name}</p>
339→                </div>
340→                <button
341→                  type="button"
342→                  onClick={() => setCreateDialog(null)}
343→                  className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
344→                  title="Close create worktree dialog"
345→                >
346→                  <X size={14} />
347→                </button>
348→              </div>
349→
350→              <div className="space-y-4 px-4 py-4">
351→                <div>
352→                  <p className="mb-2 text-[11px] font-semibold uppercase tracking-wider text-fg-subtle">
353→                    Branch mode
354→                  </p>
355→                  <div className="grid grid-cols-2 gap-2">
356→                    <button
357→                      type="button"
358→                      onClick={() => handleCreateModeChange("existing")}
359→                      disabled={createAvailableBranches.length === 0}
360→                      className={`rounded border px-3 py-2 text-left text-xs transition-colors ${
361→                        createDialog.mode === "existing"
362→                          ? "border-accent bg-accent-bg text-accent-fg"
363→                          : "border-border bg-bg-raised text-fg-muted hover:border-border-hover hover:text-fg"
364→                      } disabled:cursor-not-allowed disabled:opacity-50`}
365→                    >
366→                      Existing branch
367→                    </button>
368→                    <button
369→                      type="button"
370→                      onClick={() => handleCreateModeChange("new")}
371→                      className={`rounded border px-3 py-2 text-left text-xs transition-colors ${
372→                        createDialog.mode === "new"
373→                          ? "border-accent bg-accent-bg text-accent-fg"
374→                          : "border-border bg-bg-raised text-fg-muted hover:border-border-hover hover:text-fg"
375→                      }`}
376→                    >
377→                      New branch
378→                    </button>
379→                  </div>
380→                </div>
381→
382→                {createDialog.mode === "existing" ? (
383→                  <label className="block text-xs text-fg-muted">
384→                    Branch
385→                    <select
386→                      value={createDialog.branchName}
387→                      onChange={(event) => handleCreateBranchNameChange(event.target.value)}
388→                      className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors focus:border-accent"
389→                    >
390→                      {createAvailableBranches.map((branchName) => (
391→                        <option key={branchName} value={branchName}>
392→                          {branchName}
393→                        </option>
394→                      ))}
395→                    </select>
396→                  </label>
397→                ) : (
398→                  <label className="block text-xs text-fg-muted">
399→                    New branch name
400→                    <input
401→                      value={createDialog.branchName}
402→                      onChange={(event) => handleCreateBranchNameChange(event.target.value)}
403→                      placeholder="feature/my-worktree"
404→                      className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
405→                    />
406→                  </label>
407→                )}
408→
409→                <label className="block text-xs text-fg-muted">
410→                  Target path
411→                  <input
412→                    value={createDialog.targetPath}
413→                    onChange={(event) =>
414→                      updateCreateDialog((current) => ({
415→                        ...current,
416→                        targetPath: event.target.value,
417→                        pathEdited: true,
418→                        error: null,
419→                      }))
420→                    }
421→                    className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors focus:border-accent"
422→                  />
423→                </label>
424→
425→                {createDialog.error && (
426→                  <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
427→                    {createDialog.error}
428→                  </div>
429→                )}
430→              </div>
431→
432→              <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
433→                <button
434→                  type="button"
435→                  onClick={() => setCreateDialog(null)}
436→                  className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
437→                >
438→                  Cancel
439→                </button>
440→                <button
441→                  type="submit"
442→                  disabled={createSubmitDisabled}
443→                  className="rounded bg-accent px-3 py-2 text-xs font-medium text-white transition-colors hover:bg-accent-hover disabled:cursor-not-allowed disabled:opacity-60"
444→                >
445→                  {createWorktreeMutation.isPending ? "Creating..." : "Create worktree"}
446→                </button>
447→              </div>
448→            </form>
449→          </div>
450→        )}
451→        {deleteDialog && (
452→          <div className="fixed inset-0 z-20 flex items-center justify-center bg-black/50 p-4">
453→            <div className="w-full max-w-md rounded-lg border border-border bg-bg-overlay shadow-2xl">
454→              <div className="flex items-center border-b border-border-subtle px-4 py-3">
455→                <div className="flex-1">
456→                  <h3 className="text-sm font-semibold text-fg">Delete worktree</h3>
457→                  <p className="mt-1 text-xs text-fg-muted">{deleteDialog.worktree.branch}</p>
458→                </div>
459→                <button
460→                  type="button"
461→                  onClick={() => setDeleteDialog(null)}
462→                  className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
463→                  title="Close delete worktree dialog"
464→                >
465→                  <X size={14} />
466→                </button>
467→              </div>
468→
469→              <div className="space-y-3 px-4 py-4">
470→                <p className="text-sm text-fg-muted">
471→                  Remove this worktree checkout and delete its branch.
472→                </p>
473→                <div className="rounded border border-border bg-bg-raised px-3 py-2 text-xs text-fg-muted">
474→                  <div>Branch: {deleteDialog.worktree.branch}</div>
475→                  <div className="mt-1 break-all">Path: {deleteDialog.worktree.path}</div>
476→                </div>
477→                {deleteDialog.error && (
478→                  <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
479→                    {deleteDialog.error}
480→                  </div>
481→                )}
482→              </div>
483→
484→              <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
485→                <button
486→                  type="button"
487→                  onClick={() => setDeleteDialog(null)}
488→                  className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
489→                >
490→                  Cancel
491→                </button>
492→                {deleteDialog.forceAvailable && (
493→                  <button
494→                    type="button"
495→                    onClick={() => void handleDeleteSubmit(true)}
496→                    disabled={deleteWorktreeMutation.isPending}
497→                    className="rounded border border-red px-3 py-2 text-xs font-medium text-red transition-colors hover:bg-red-bg disabled:cursor-not-allowed disabled:opacity-60"
498→                  >
499→                    Force delete
500→                  </button>
501→                )}
502→                <button
503→                  type="button"
504→                  onClick={() => void handleDeleteSubmit(false)}
505→                  disabled={deleteWorktreeMutation.isPending}
506→                  className="rounded bg-red px-3 py-2 text-xs font-medium text-white transition-colors hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60"
507→                >
508→                  {deleteWorktreeMutation.isPending ? "Deleting..." : "Delete worktree"}
509→                </button>
510→              </div>
511→            </div>
512→          </div>
513→        )}
514→      </>
515→    );
516→  }
517→
518→  return (
519→    <>
520→      <div
521→        className="flex shrink-0 flex-col border-r border-border bg-bg-raised"
522→        style={{ width }}
523→      >
524→        <div className="flex items-center border-b border-border-subtle p-4">
525→          <h2 className="flex flex-1 items-center gap-2 text-[15px] font-semibold text-fg">
526→            <FolderGit2 size={18} />
527→            Repositories
528→          </h2>
529→          <button
530→            onClick={handleAddRepo}
531→            className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
532→            title="Add repository"
533→          >
534→            <FolderPlus size={14} />
535→          </button>
536→          <button
537→            onClick={() => setCollapsed(true)}
538→            className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
539→            title="Collapse sidebar"
540→          >
541→            <PanelLeftClose size={14} />
542→          </button>
543→        </div>
544→
545→        <div className="flex-1 overflow-y-auto py-3">
546→          <button
547→            onClick={() => setRepoListCollapsed(!repoListCollapsed)}
548→            className="mb-1 flex w-full items-center gap-2 px-4 text-left"
549→          >
550→            {repoListCollapsed ? (
551→              <ChevronRight size={10} className="text-fg-subtle" />
552→            ) : (
553→              <ChevronDown size={10} className="text-fg-subtle" />
554→            )}
555→            <span className="text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
556→              Active
557→            </span>
558→            {isLoading && <Loader2 size={10} className="animate-spin text-fg-subtle" />}
559→          </button>
560→
561→          {error && !repoListCollapsed && (
562→            <div className="px-4 py-2 text-[11px] text-red">Failed to load repos</div>
563→          )}
564→
565→          {sidebarError && !repoListCollapsed && (
566→            <div className="mx-4 mb-2 rounded bg-red-bg px-2 py-1.5 text-[11px] text-red">
567→              {sidebarError}
568→              <button
569→                onClick={() => setSidebarError(null)}
570→                className="ml-1 text-fg-subtle hover:text-fg"
571→              >
572→                <X size={10} className="inline" />
573→              </button>
574→            </div>
575→          )}
576→
577→          {!repoListCollapsed &&
578→            repos.map((repo) => {
579→              const repoRefreshing = isRepoRefreshing(refreshingRepoPath, repo.path);
580→
581→              return (
582→                <div key={repo.path}>
583→                  <div className="group flex items-center">
584→                    <button
585→                      onClick={() => toggleRepo(repo.path)}
586→                      className="flex flex-1 items-center gap-2.5 px-4 py-[7px] text-[13px] text-fg-muted transition-colors hover:bg-bg-hover hover:text-fg"
587→                    >
588→                      {expandedRepos.has(repo.path) ? (
589→                        <ChevronDown size={14} />
590→                      ) : (
591→                        <ChevronRight size={14} />
592→                      )}
593→                      <BookOpen size={14} />
594→                      {repo.name}
595→                      <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
596→                        {repo.branches.length}
597→                      </span>
598→                    </button>
599→                    <button
600→                      onClick={(event) => {
601→                        event.stopPropagation();
602→                        handleOpenCreateDialog(repo);
603→                      }}
604→                      className="mr-1 flex h-5 w-5 items-center justify-center rounded transition-opacity hover:bg-bg-hover opacity-0 group-hover:opacity-100"
605→                      title="Create worktree"
606→                    >
607→                      <Plus size={12} className="text-fg-subtle" />
608→                    </button>
609→                    <button
610→                      onClick={(event) => {
611→                        event.stopPropagation();
612→                        void handleRefreshRepo(repo.path);
613→                      }}
614→                      disabled={repoRefreshing}
615→                      className={`mr-1 flex h-5 w-5 items-center justify-center rounded transition-opacity hover:bg-bg-hover ${
