189→export function useBranchTranscriptsQuery(
190→  repoPath: string,
191→  branch: string,
192→  enabled: boolean
193→) {
194→  const { data: checkpoints } = useCheckpointsQuery(repoPath, branch);
195→
196→  const queries = useQueries({
197→    queries: (checkpoints ?? []).map((cp) => ({
198→      queryKey: ["transcript", repoPath, cp.checkpoint_id, 0] as const,
199→      queryFn: () =>
200→        invoke<TranscriptMessage[]>("get_transcript", {
201→          repoPath,
202→          checkpointId: cp.checkpoint_id,
203→          sessionIndex: 0,
204→        }),
205→      enabled: enabled && !!repoPath && !!cp.checkpoint_id,
206→      retry: false,
207→    })),
208→  });
209→
210→  return { checkpoints: checkpoints ?? [], queries };
211→}
