102→#[tauri::command]
103→fn get_transcript(
104→    repo_path: String,
105→    checkpoint_id: String,
106→    session_index: u32,
107→) -> Result<Vec<session::TranscriptMessage>, String> {
108→    let repo = git::open_repo(&repo_path)?;
109→
110→    let prefix = &checkpoint_id[..2];
111→    let suffix = &checkpoint_id[2..];
112→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
113→    let meta_content = read_blob(&repo, &meta_path).ok();
114→    let candidates =
115→        transcript_candidate_paths(&checkpoint_id, session_index, meta_content.as_deref());
116→
117→    for path in &candidates {
118→        if let Ok(content) = read_blob(&repo, path) {
119→            return Ok(session::read_transcript(&content));
120→        }
121→    }
122→
123→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
124→}
