126→fn transcript_candidate_paths(
127→    checkpoint_id: &str,
128→    session_index: u32,
129→    meta_content: Option<&str>,
130→) -> Vec<String> {
131→    let prefix = &checkpoint_id[..2];
132→    let suffix = &checkpoint_id[2..];
133→    let requested_session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
134→    let mut candidates = Vec::new();
135→
136→    let mut push_candidate = |path: String| {
137→        if !path.is_empty() && !candidates.contains(&path) {
138→            candidates.push(path);
139→        }
140→    };
141→
142→    if let Some(meta_content) = meta_content {
143→        if let Ok(meta) = serde_json::from_str::<serde_json::Value>(meta_content) {
144→            if let Some(sessions) = meta.get("sessions").and_then(|s| s.as_array()) {
145→                let mut ordered_sessions = Vec::new();
146→                if let Some(session) = sessions.get(session_index as usize) {
147→                    ordered_sessions.push(session);
148→                }
149→                for (idx, session) in sessions.iter().enumerate() {
150→                    if idx != session_index as usize {
151→                        ordered_sessions.push(session);
152→                    }
153→                }
154→
155→                for session in ordered_sessions {
156→                    if let Some(path) = session.get("transcript").and_then(|p| p.as_str()) {
157→                        push_candidate(path.trim_start_matches('/').to_string());
158→                    }
159→                }
160→            }
161→        }
162→    }
163→
164→    push_candidate(format!("{}/full.jsonl", requested_session_dir));
165→    push_candidate(format!("{}/transcript.jsonl", requested_session_dir));
166→    candidates
167→}
