169→/// Read a blob from the entire/checkpoints/v1 branch by path
170→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
171→    let branch_ref = repo
172→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
173→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
174→
175→    let commit = branch_ref
176→        .get()
177→        .peel_to_commit()
178→        .map_err(|e| format!("Failed to peel: {}", e))?;
179→
180→    let tree = commit
181→        .tree()
182→        .map_err(|e| format!("Failed to get tree: {}", e))?;
183→
184→    let entry = tree
185→        .get_path(std::path::Path::new(path))
186→        .map_err(|e| format!("Path not found: {}", e))?;
187→
188→    let blob = repo
189→        .find_blob(entry.id())
190→        .map_err(|e| format!("Failed to read blob: {}", e))?;
191→
192→    std::str::from_utf8(blob.content())
193→        .map(|s| s.to_string())
194→        .map_err(|e| format!("Invalid UTF-8: {}", e))
195→}
