229→#[derive(serde::Serialize)]
230→struct EntireLogResult {
231→    lines: Vec<String>,
232→    total_lines: u32,
233→    file_size_bytes: u64,
234→}
235→
236→#[tauri::command]
237→fn get_entire_logs(repo_path: String, tail_lines: u32) -> Result<EntireLogResult, String> {
238→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
239→    if !log_path.exists() {
240→        return Err("No log file found".to_string());
241→    }
242→
243→    let metadata = std::fs::metadata(&log_path)
244→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
245→    let file_size_bytes = metadata.len();
246→
247→    let file = std::fs::File::open(&log_path)
248→        .map_err(|e| format!("Failed to open log file: {}", e))?;
249→
250→    // Count total lines
251→    let reader = BufReader::new(&file);
252→    let all_lines: Vec<String> = reader.lines().filter_map(|l| l.ok()).collect();
253→    let total_lines = all_lines.len() as u32;
254→
255→    // Take last N lines
256→    let start = all_lines.len().saturating_sub(tail_lines as usize);
257→    let lines = all_lines[start..].to_vec();
258→
259→    Ok(EntireLogResult {
260→        lines,
261→        total_lines,
262→        file_size_bytes,
263→    })
264→}
