266→#[tauri::command]
267→fn get_checkpoint_logs(
268→    repo_path: String,
269→    checkpoint_id: String,
270→    session_ids: Vec<String>,
271→) -> Result<EntireLogResult, String> {
272→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
273→    if !log_path.exists() {
274→        return Ok(EntireLogResult {
275→            lines: Vec::new(),
276→            total_lines: 0,
277→            file_size_bytes: 0,
278→        });
279→    }
280→
281→    let metadata = std::fs::metadata(&log_path)
282→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
283→    let file_size_bytes = metadata.len();
284→
285→    let file = std::fs::File::open(&log_path)
286→        .map_err(|e| format!("Failed to open log file: {}", e))?;
287→
288→    let reader = BufReader::new(file);
289→    let mut matching_lines = Vec::new();
290→
291→    for line in reader.lines() {
292→        let line = match line {
293→            Ok(l) => l,
294→            Err(_) => continue,
295→        };
296→
297→        // Parse each line as JSON and check for matching session_id or checkpoint_id
298→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(&line) {
299→            let line_session_id = value.get("session_id").and_then(|v| v.as_str());
300→            let line_checkpoint_id = value.get("checkpoint_id").and_then(|v| v.as_str());
301→
302→            let matches = line_session_id
303→                .map(|sid| session_ids.iter().any(|s| s == sid))
304→                .unwrap_or(false)
305→                || line_checkpoint_id
306→                    .map(|cid| cid == checkpoint_id)
307→                    .unwrap_or(false);
308→
309→            if matches {
310→                matching_lines.push(line);
311→            }
312→        }
313→    }
314→
315→    Ok(EntireLogResult {
316→        total_lines: matching_lines.len() as u32,
317→        lines: matching_lines,
318→        file_size_bytes,
319→    })
320→}
