408→/// Convert a git2::Diff into our FileDiff structs
409→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
410→    let mut files: Vec<FileDiff> = Vec::new();
411→
412→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
413→        let path = delta
414→            .new_file()
415→            .path()
416→            .or_else(|| delta.old_file().path())
417→            .map(|p| p.to_string_lossy().to_string())
418→            .unwrap_or_default();
419→
420→        let status = match delta.status() {
421→            git2::Delta::Added => "added",
422→            git2::Delta::Deleted => "deleted",
423→            _ => "modified",
424→        };
425→
426→        // Ensure we have a FileDiff entry for this path
427→        if files.last().map_or(true, |f| f.path != path) {
428→            files.push(FileDiff {
429→                path: path.clone(),
430→                status: status.to_string(),
431→                hunks: Vec::new(),
432→            });
433→        }
434→
435→        let file = files.last_mut().unwrap();
436→
437→        // New hunk
438→        if let Some(h) = hunk {
439→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
440→            if file.hunks.last().map_or(true, |last| last.header != header) {
441→                file.hunks.push(DiffHunk {
442→                    header,
443→                    lines: Vec::new(),
444→                });
445→            }
446→        }
447→
448→        // Diff line
449→        if let Some(current_hunk) = file.hunks.last_mut() {
450→            let kind = match line.origin() {
451→                '+' => "add",
452→                '-' => "delete",
453→                ' ' => "context",
454→                _ => return true,
455→            };
456→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
457→            current_hunk.lines.push(DiffLine {
458→                kind: kind.to_string(),
459→                content,
460→                old_lineno: line.old_lineno(),
461→                new_lineno: line.new_lineno(),
462→            });
463→        }
464→
465→        true
466→    })
467→    .map_err(|e| format!("Failed to print diff: {}", e))?;
468→
469→    Ok(files)
470→}
