472→fn collect_checkpoint_diff(
473→    repo: &git2::Repository,
474→    commit_sha: &str,
475→) -> Result<Vec<FileDiff>, String> {
476→    let oid = git2::Oid::from_str(commit_sha)
477→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
478→    let commit = repo
479→        .find_commit(oid)
480→        .map_err(|e| format!("Commit not found: {}", e))?;
481→
482→    let tree = commit
483→        .tree()
484→        .map_err(|e| format!("Failed to get tree: {}", e))?;
485→
486→    let parent_tree = commit.parent(0).ok().and_then(|p| p.tree().ok());
487→
488→    let diff = repo
489→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
490→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
491→
492→    collect_diff_files(&diff)
493→}
