495→fn load_sanitized_checkpoint_transcripts(
496→    repo: &git2::Repository,
497→    checkpoint_id: &str,
498→) -> Result<Vec<semantic_review::PromptTranscriptSession>, String> {
499→    let prefix = &checkpoint_id[..2];
500→    let suffix = &checkpoint_id[2..];
501→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
502→    let meta_content = read_blob(repo, &meta_path)?;
503→    let meta = serde_json::from_str::<CheckpointReviewMetadata>(&meta_content)
504→        .map_err(|e| format!("Failed to parse checkpoint metadata: {}", e))?;
505→
506→    let session_count = meta.sessions.map(|sessions| sessions.len()).unwrap_or(0);
507→    let mut all_sessions = Vec::new();
508→
509→    for session_index in 0..session_count {
510→        let candidates =
511→            transcript_candidate_paths(checkpoint_id, session_index as u32, Some(&meta_content));
512→        let mut transcript_content = None;
513→        for path in candidates {
514→            if let Ok(content) = read_blob(repo, &path) {
515→                transcript_content = Some(content);
516→                break;
517→            }
518→        }
519→
520→        let Some(content) = transcript_content else {
521→            continue;
522→        };
523→
524→        let parsed = session::read_transcript(&content);
525→        let sanitized = session::sanitize_transcript_for_semantic_review(&parsed, 4_000);
526→        if sanitized.is_empty() {
527→            continue;
528→        }
529→
530→        all_sessions.push(semantic_review::PromptTranscriptSession {
531→            session_index: session_index as u32,
532→            messages: sanitized
533→                .into_iter()
534→                .map(|message| semantic_review::PromptTranscriptMessage {
535→                    role: message.role,
536→                    content: message.content,
537→                })
538→                .collect(),
539→        });
540→    }
541→
542→    Ok(all_sessions)
543→}
