545→fn call_anthropic_semantic_review(prompt: &str) -> Result<String, String> {
546→    let api_key = std::env::var("ANTHROPIC_API_KEY")
547→        .map_err(|_| "ANTHROPIC_API_KEY is not set".to_string())?;
548→    let model = std::env::var("ANTHROPIC_MODEL")
549→        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
550→
551→    let client = reqwest::blocking::Client::builder()
552→        .timeout(std::time::Duration::from_secs(90))
553→        .build()
554→        .map_err(|e| format!("Failed to build Anthropic client: {}", e))?;
555→
556→    let response = client
557→        .post("https://api.anthropic.com/v1/messages")
558→        .header("x-api-key", api_key)
559→        .header("anthropic-version", "2023-06-01")
560→        .header("content-type", "application/json")
561→        .json(&AnthropicRequest {
562→            model,
563→            max_tokens: 2_000,
564→            temperature: 0.2,
565→            system: "You are reviewing a git diff. Return JSON only with precise, line-linked explanations of the most important changes.".to_string(),
566→            messages: vec![AnthropicMessage {
567→                role: "user".to_string(),
568→                content: prompt.to_string(),
569→            }],
570→        })
571→        .send()
572→        .map_err(|e| format!("Anthropic request failed: {}", e))?
573→        .error_for_status()
574→        .map_err(|e| format!("Anthropic request failed: {}", e))?;
575→
576→    let body: AnthropicResponse = response
577→        .json()
578→        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
579→
580→    let text = body
581→        .content
582→        .into_iter()
583→        .filter(|block| block.kind == "text")
584→        .filter_map(|block| block.text)
585→        .collect::<Vec<_>>()
586→        .join("\n");
587→
588→    if text.trim().is_empty() {
589→        return Err("Anthropic response did not include any text output".to_string());
590→    }
591→
592→    Ok(text)
593→}
