615→#[tauri::command]
616→fn run_checkpoint_semantic_review(
617→    repo_path: String,
618→    checkpoint_id: String,
619→    commit_sha: String,
620→) -> Result<semantic_review::RunCheckpointSemanticReviewResponse, String> {
621→    if checkpoint_id.len() < 2 {
622→        return Err("Invalid checkpoint ID".to_string());
623→    }
624→    if commit_sha.is_empty() {
625→        return Err("No commit SHA available for this checkpoint".to_string());
626→    }
627→
628→    let repo = git::open_repo(&repo_path)?;
629→    let files = collect_checkpoint_diff(&repo, &commit_sha)?;
630→    if files.is_empty() {
631→        return Ok(semantic_review::RunCheckpointSemanticReviewResponse {
632→            review_run_id: generate_review_run_id(),
633→            annotations: Vec::new(),
634→        });
635→    }
636→
637→    let transcripts = load_sanitized_checkpoint_transcripts(&repo, &checkpoint_id)?;
638→    let prompt = semantic_review::build_prompt(&files, &transcripts);
639→    let raw_text = call_anthropic_semantic_review(&prompt)?;
640→    let parsed = semantic_review::parse_response_text(&raw_text)?;
641→    let annotations = semantic_review::resolve_annotations(&files, parsed);
642→
643→    Ok(semantic_review::RunCheckpointSemanticReviewResponse {
644→        review_run_id: generate_review_run_id(),
645→        annotations,
646→    })
647→}
