649→#[tauri::command]
650→fn get_branch_diff(
651→    repo_path: String,
652→    branch: String,
653→) -> Result<Vec<FileDiff>, String> {
654→    let repo = git::open_repo(&repo_path)?;
655→
656→    // Resolve the branch HEAD
657→    let branch_ref = repo
658→        .find_branch(&branch, git2::BranchType::Local)
659→        .map_err(|e| format!("Branch not found: {}", e))?;
660→    let branch_commit = branch_ref
661→        .get()
662→        .peel_to_commit()
663→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
664→
665→    // Find the default branch (try main, then master)
666→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
667→        "main"
668→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
669→        "master"
670→    } else {
671→        return Err("No default branch (main/master) found".to_string());
672→    };
673→
674→    // If we're diffing the default branch against itself, return empty
675→    if branch == default_branch_name {
676→        return Ok(Vec::new());
677→    }
678→
679→    let default_ref = repo
680→        .find_branch(default_branch_name, git2::BranchType::Local)
681→        .map_err(|e| format!("Default branch error: {}", e))?;
682→    let default_commit = default_ref
683→        .get()
684→        .peel_to_commit()
685→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
686→
687→    // Find merge base
688→    let merge_base_oid = repo
689→        .merge_base(default_commit.id(), branch_commit.id())
690→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
691→    let merge_base_commit = repo
692→        .find_commit(merge_base_oid)
693→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
694→
695→    let base_tree = merge_base_commit
696→        .tree()
697→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
698→    let branch_tree = branch_commit
699→        .tree()
700→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
701→
702→    let diff = repo
703→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
704→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
705→
706→    collect_diff_files(&diff)
707→}
