710→fn watch_repo(
711→    repo_path: String,
712→    app: tauri::AppHandle,
713→    state: State<'_, Mutex<AppState>>,
714→) -> Result<(), String> {
715→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
716→
717→    // Don't double-watch
718→    if app_state.watched_repos.contains(&repo_path) {
719→        return Ok(());
720→    }
721→    app_state.watched_repos.insert(repo_path.clone());
722→
723→    let app_handle = app.clone();
