739→#[cfg_attr(mobile, tauri::mobile_entry_point)]
740→pub fn run() {
741→    tauri::Builder::default()
742→        .plugin(tauri_plugin_opener::init())
743→        .plugin(tauri_plugin_dialog::init())
744→        .plugin(tauri_plugin_window_state::Builder::default().build())
745→        .manage(Mutex::new(AppState {
746→            watched_repos: HashSet::new(),
747→        }))
748→        .manage(Mutex::new(ghostty::GhosttyState::new()))
749→        .setup(|app| {
750→            // Start the ghostty tick loop on the MAIN THREAD via a Cocoa timer.
751→            // ghostty_app_tick processes Cocoa/Metal events and must run on the
752→            // main thread.
753→            {
754→                use block2::RcBlock;
755→                use objc2_foundation::NSTimer;
756→
757→                let handle = app.handle().clone();
758→                let tick_block = RcBlock::new(move |_timer| {
759→                    let state = handle.state::<Mutex<ghostty::GhosttyState>>();
760→                    let mutex = state.inner();
761→                    if let Ok(gs) = mutex.lock() {
762→                        if let Some(app) = gs.app.as_ref() {
763→                            app.tick();
764→                        }
765→                    }
766→                });
767→
768→                let _tick_timer = unsafe {
769→                    NSTimer::scheduledTimerWithTimeInterval_repeats_block(
770→                        1.0 / 60.0,
771→                        true,
772→                        &tick_block,
773→                    )
774→                };
775→            }
776→
777→            // System tray
778→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
779→            use tauri::tray::TrayIconBuilder;
780→            use tauri::Manager;
781→
782→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
783→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
784→            let menu = MenuBuilder::new(app)
785→                .item(&show)
786→                .separator()
787→                .item(&quit)
788→                .build()?;
789→
790→            let _tray = TrayIconBuilder::new()
791→                .tooltip("Entire Desktop")
792→                .menu(&menu)
793→                .on_menu_event(move |app, event| {
794→                    match event.id().as_ref() {
795→                        "show" => {
796→                            if let Some(window) = app.get_webview_window("main") {
797→                                let _ = window.show();
798→                                let _ = window.set_focus();
799→                            }
800→                        }
801→                        "quit" => {
802→                            app.exit(0);
803→                        }
804→                        _ => {}
805→                    }
806→                })
807→                .on_tray_icon_event(|tray, event| {
808→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
809→                        let app = tray.app_handle();
810→                        if let Some(window) = app.get_webview_window("main") {
811→                            let _ = window.show();
812→                            let _ = window.set_focus();
813→                        }
814→                    }
815→                })
816→                .build(app)?;
817→
818→            Ok(())
819→        })
820→        .invoke_handler(tauri::generate_handler![
821→            debug_log,
822→            list_repos,
823→            register_repo,
824→            unregister_repo,
825→            create_worktree,
826→            delete_worktree,
827→            delete_branch,
828→            list_checkpoints,
829→            get_transcript,
830→            get_checkpoint_diff,
831→            run_checkpoint_semantic_review,
832→            get_branch_diff,
833→            list_sessions,
834→            get_entire_settings,
835→            get_entire_logs,
836→            get_checkpoint_logs,
837→            get_raw_checkpoint_metadata,
838→            get_raw_session_file,
839→            launch_ghostty_agent,
840→            list_trails,
841→            watch_repo,
842→            ghostty::commands::ghostty_create_surface,
843→            ghostty::commands::ghostty_destroy_surface,
844→            ghostty::commands::ghostty_update_overlay,
845→            ghostty::commands::ghostty_show_overlay,
846→            ghostty::commands::ghostty_focus_overlay,
847→            ghostty::commands::ghostty_send_text,
848→        ])
849→        .run(tauri::generate_context!())
