 92→fn detect_worktree_branch(wt_path: &str) -> Option<String> {
 93→    let head_path = Path::new(wt_path).join(".git");
 94→    // Worktree .git is a file pointing to the main repo's worktree dir
 95→    if head_path.is_file() {
 96→        if let Ok(repo) = Repository::open(wt_path) {
 97→            if let Ok(head) = repo.head() {
 98→                return head.shorthand().map(|s| s.to_string());
 99→            }
100→        }
101→    }
102→    None
103→}
