201→pub fn create_worktree(
202→    repo_path: &str,
203→    mode: &str,
204→    branch_name: &str,
205→    target_path: &str,
206→) -> Result<(), String> {
207→    let mode = validate_worktree_request(mode, branch_name, target_path)?;
208→    open_repo(repo_path)?;
