146→fn save_hidden_repos(repos: &[String]) -> Result<(), String> {
147→    let path = hidden_registry_path();
148→    if let Some(parent) = path.parent() {
149→        fs::create_dir_all(parent).map_err(|e| format!("Failed to create ~/.entire: {}", e))?;
150→    }
