157→}
158→
159→pub fn hide_repo(path: &str) -> Result<(), String> {
160→    let canonical = Path::new(path)
161→        .canonicalize()
162→        .map(|p| p.to_string_lossy().to_string())
163→        .unwrap_or_else(|_| path.to_string());
164→
165→    let mut repos = load_hidden_repos();
166→    if !repos.contains(&canonical) {
167→        repos.push(canonical);
168→    }
169→    save_hidden_repos(&repos)
170→}
