176→/// Discover repos with Entire enabled by scanning common directories
177→pub fn discover_repos() -> Vec<String> {
178→    let mut seen = HashSet::new();
179→    let mut repos = Vec::new();
180→    let home = dirs_next().unwrap_or_default();
181→    let hidden = get_hidden_repos();
182→
183→    // Scan common project directories
184→    let scan_dirs = vec![
185→        PathBuf::from(&home).join("Projects"),
186→        PathBuf::from(&home).join("code"),
187→        PathBuf::from(&home).join("src"),
188→        PathBuf::from(&home).join("dev"),
189→    ];
190→
191→    for dir in scan_dirs {
192→        if dir.exists() {
193→            if let Ok(entries) = fs::read_dir(&dir) {
194→                for entry in entries.flatten() {
195→                    let path = entry.path();
196→                    if path.is_dir() && is_entire_enabled(&path.to_string_lossy()) {
197→                        let s = path.to_string_lossy().to_string();
198→                        if seen.insert(s.clone()) {
199→                            repos.push(s);
200→                        }
201→                    }
202→                }
203→            }
204→        }
205→    }
206→
207→    // Merge in manually registered repos
208→    for registered in load_registered_repos() {
209→        if seen.insert(registered.clone()) {
210→            // Only add if the repo still exists and is still enabled
211→            if Path::new(&registered).is_dir() && is_entire_enabled(&registered) {
212→                repos.push(registered);
213→            }
214→        }
215→    }
216→
217→    repos
218→}
219→
220→fn dirs_next() -> Option<String> {
221→    std::env::var("HOME").ok()
222→}
