24→export function buildCreateWorktreeDraft(repo: RepoLike): CreateWorktreeDraft {
25→  const worktreeBranches = new Set(repo.worktrees.map((worktree) => worktree.branch));
26→  const firstAvailableBranch = repo.branches.find(
