22→  const remainingTabs = state.tabs.filter((tab) => tab.repoPath !== state.worktreePath);
23→  const activeTabRemoved = removedTabs.some((tab) => tab.id === state.activeTabId);
24→
25→  return {
26→    remainingTabs,
27→    removedTabIds: removedTabs.map((tab) => tab.id),
28→    nextActiveTabId: activeTabRemoved ? remainingTabs[0]?.id ?? null : state.activeTabId,
29→  };
30→}
