          <button
            onClick={handleAddRepo}
            className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title="Add repository"
          >
            <FolderPlus size={14} />
          </button>
          <button
            onClick={() => setCollapsed(true)}
            className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title="Collapse sidebar"
