    className="mr-2 flex h-5 w-5 items-center justify-center rounded opacity-0 transition-opacity hover:bg-bg-hover group-hover:opacity-100"
    title="Remove registered repo"
  >
    <X size={12} className="text-fg-subtle" />
  </button>
)}

