351→    }
352→    const closedWorkspace = workspaceMap.get(tabId);
353→    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
354→      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
355→    }
356→    setWorkspaceMap((prev) => {
357→      const next = new Map(prev);
358→      next.delete(tabId);
359→      return next;
360→    });
361→  }
