140→): TerminalWorkspace {
141→  return updateTerminalTab(workspace, terminalTabId, (terminalTab) => {
142→    if (terminalTab.panes.length === 1) return terminalTab;
143→
144→    const panes = terminalTab.panes.filter((pane) => pane.id !== paneId);
145→    return {
146→      ...terminalTab,
147→      splitDirection: null,
