154→export function closeTerminalTabInWorkspace(
155→  workspace: TerminalWorkspace,
156→  terminalTabId: string
157→): TerminalWorkspace {
158→  const terminalTabs = workspace.terminalTabs.filter(
159→    (terminalTab) => terminalTab.id !== terminalTabId
160→  );
161→
162→  if (terminalTabs.length === 0) {
163→    return createTerminalWorkspace();
164→  }
165→
166→  const activeTerminalTabId =
167→    workspace.activeTerminalTabId === terminalTabId
168→      ? terminalTabs[Math.max(0, workspace.terminalTabs.findIndex(
169→          (terminalTab) => terminalTab.id === terminalTabId
170→        ) - 1)]?.id ?? terminalTabs[0].id
171→      : workspace.activeTerminalTabId;
172→
173→  return {
174→    terminalTabs,
175→    activeTerminalTabId,
176→  };
177→}
