222→export function resolveAgentLaunchTarget(
223→  workspace: TerminalWorkspace
224→): AgentLaunchTarget {
225→  const activeTerminalTab = workspace.terminalTabs.find(
226→    (terminalTab) => terminalTab.id === workspace.activeTerminalTabId
227→  );
228→  const activePane = activeTerminalTab?.panes.find(
229→    (pane) => pane.id === activeTerminalTab.activePaneId
230→  );
231→
232→  if (!activeTerminalTab || !activePane || activePane.session) {
233→    return { mode: "create-terminal-tab" };
234→  }
