243→export function resolveAutoLaunchTarget(
244→  workspace: TerminalWorkspace
245→): AutoLaunchTarget | null {
246→  const activeTerminalTab = workspace.terminalTabs.find(
247→    (terminalTab) => terminalTab.id === workspace.activeTerminalTabId
248→  );
249→  const pane = activeTerminalTab?.panes.find(
250→    (candidate) => candidate.shouldAutoLaunch && !candidate.session
