211→/// Focus the native overlay so it receives keyboard input.
212→#[tauri::command]
213→pub fn ghostty_focus_overlay(
214→    surface_id: String,
215→    state: State<'_, Mutex<super::GhosttyState>>,
216→) -> Result<(), String> {
217→    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
218→    let entry = gs
219→        .surfaces
220→        .get(&surface_id)
221→        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;
222→
223→    if let Some(app) = gs.app.as_ref() {
224→        app.set_focus(true);
225→        debug_log("ghostty_focus_overlay: app focus set true");
226→    }
227→    let focused = entry.overlay.focus();
228→    debug_log(&format!(
229→        "ghostty_focus_overlay: makeFirstResponder result={}",
230→        focused
231→    ));
232→    entry.surface.set_focus(true);
233→    Ok(())
