 75→impl GhosttyInputMods {
 76→    pub const NONE: Self = Self(0);
 77→    pub const SHIFT: Self = Self(1 << 0);
 78→    pub const CTRL: Self = Self(1 << 1);
 79→    pub const ALT: Self = Self(1 << 2);
 80→    pub const SUPER: Self = Self(1 << 3);
 81→
 82→    pub fn contains(self, other: Self) -> bool {
 83→        (self.0 & other.0) == other.0
 84→    }
 85→}
