 87→impl BitOr for GhosttyInputMods {
 88→    type Output = Self;
 89→
 90→    fn bitor(self, rhs: Self) -> Self::Output {
 91→        Self(self.0 | rhs.0)
 92→    }
 93→}
 94→
 95→impl BitOrAssign for GhosttyInputMods {
 96→    fn bitor_assign(&mut self, rhs: Self) {
 97→        self.0 |= rhs.0;
 98→    }
 99→}
