/// Create a new surface attached to the given NSView.
pub fn new(
    app: &GhosttyApp,
    nsview: *mut c_void,
    working_dir: Option<&str>,
    command: Option<&str>,
    scale_factor: f64,
) -> Result<Self, String> {
    let working_dir_c = working_dir.map(|s| CString::new(s).unwrap());
    let command_c = command.map(|s| CString::new(s).unwrap());

    let wd_ptr = working_dir_c.as_ref().map_or(ptr::null(), |s| s.as_ptr());
    let cmd_ptr = command_c.as_ref().map_or(ptr::null(), |s| s.as_ptr());

    let mut config = unsafe { ghostty_surface_config_new() };
    config.platform_tag = GhosttyPlatform::MacOS;
    config.platform = GhosttyPlatformUnion { nsview };
    config.userdata = ptr::null_mut();
    config.scale_factor = scale_factor;
    config.font_size = 0.0; // 0 = use config default
    config.working_directory = wd_ptr;
    config.command = cmd_ptr;
    config.env_vars = ptr::null_mut();
    config.env_var_count = 0;
    config.initial_input = ptr::null();
    config.wait_after_command = false;
    config.context = GhosttySurfaceContext::Split;

