    format!("ghostty-{}-{}", now.as_secs(), now.subsec_nanos())
}

fn resolve_surface_command(command: Option<&str>) -> Option<&str> {
    match command {
        Some("claude-code") => Some("claude"),
        Some("codex") => Some("codex"),
        Some("terminal") | None => None,
        Some(other) => Some(other),
    }
}

/// Create a new libghostty surface with a native NSView overlay.
///
/// The surface spawns its own PTY internally. If `command` is provided
/// (e.g., "claude" or "codex"), libghostty will run that command instead
/// of the default shell.
#[tauri::command]
pub fn ghostty_create_surface(
    window: WebviewWindow,
    working_dir: String,
    command: Option<String>,
    initial_input: Option<String>,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<String, String> {
    debug_log(&format!(
        "ghostty_create_surface called: working_dir={:?}, command={:?}",
        working_dir, command
    ));

    let mut gs = state.lock().map_err(|e| {
        let msg = format!("State lock error: {}", e);
        debug_log(&msg);
        msg
    })?;

    // Ensure the ghostty app is initialized
    debug_log("Ensuring ghostty app is initialized...");
    gs.ensure_app().map_err(|e| {
        debug_log(&format!("ensure_app FAILED: {}", e));
        e
    })?;
    if let Some(app) = gs.app.as_ref() {
        app.set_focus(true);
        debug_log("ghostty app focus set true");
    }
    debug_log("ghostty app initialized OK");

    // Get the native window handle for overlay placement
    debug_log("Getting NSWindow handle...");
    let ns_window = overlay::get_nswindow(&window).map_err(|e| {
        debug_log(&format!("get_nswindow FAILED: {}", e));
        e
    })?;
    debug_log(&format!("NSWindow handle OK: {:?}", ns_window));

    // Create the native NSView overlay
    debug_log("Creating GhosttyOverlay (NSView + CAMetalLayer)...");
    let overlay = unsafe {
        GhosttyOverlay::new(ns_window).map_err(|e| {
            debug_log(&format!("GhosttyOverlay::new FAILED: {}", e));
            e
        })?
    };
    let nsview_ptr = overlay.nsview_ptr();
    debug_log(&format!("Overlay created OK, nsview_ptr={:?}", nsview_ptr));

    // Get the window's backing scale factor for Retina displays
    let scale_factor = window.scale_factor().unwrap_or(2.0);
    debug_log(&format!("scale_factor={}", scale_factor));

    // Resolve the command — map agent names to CLI binaries
    let resolved_command = resolve_surface_command(command.as_deref());
    debug_log(&format!("resolved_command={:?}", resolved_command));

    // Create the libghostty surface
    debug_log("Creating GhosttySurface (ghostty_surface_new FFI call)...");
    let app = gs.app.as_ref().unwrap();
    let surface = GhosttySurface::new(
        app,
        nsview_ptr,
        Some(&working_dir),
        resolved_command,
        scale_factor,
    )
    .map_err(|e| {
        debug_log(&format!("GhosttySurface::new FAILED: {}", e));
        e
    })?;
    overlay.set_surface(surface.raw());
    debug_log("GhosttySurface created OK");

    let surface_id = generate_surface_id();
    gs.surfaces
        .insert(surface_id.clone(), SurfaceEntry { surface, overlay });

    debug_log(&format!("Surface registered with id={}", surface_id));
    Ok(surface_id)
}

/// Destroy a surface and remove its native overlay.
#[tauri::command]
pub fn ghostty_destroy_surface(
    surface_id: String,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;
    if let Some(entry) = gs.surfaces.remove(&surface_id) {
        entry.overlay.clear_surface();
        drop(entry);
    }
    // Drop handles cleanup: GhosttySurface::drop frees the libghostty surface,
    // GhosttyOverlay::drop removes the NSView from its superview.
    Ok(())
}

/// Reposition the native overlay to match the terminal panel's position in the webview.
///
/// Coordinates are in CSS pixels with top-left origin (matching getBoundingClientRect).
#[tauri::command]
pub fn ghostty_update_overlay(
    surface_id: String,
    x: f64,
    y: f64,
    width: f64,
    height: f64,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
    let entry = gs
        .surfaces
        .get(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    // Update the NSView frame to match
    entry.overlay.update_frame(x, y, width, height);

    // Also update the libghostty surface size (in physical pixels for Metal)
    let scale = 2.0; // TODO: get actual scale factor
    entry
        .surface
        .set_size((width * scale) as u32, (height * scale) as u32);

    Ok(())
}

/// Show or hide the native overlay (for terminal panel toggle).
#[tauri::command]
pub fn ghostty_show_overlay(
    surface_id: String,
    visible: bool,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;
    if visible {
        if let Some(app) = gs.app.as_ref() {
            app.set_focus(true);
            debug_log("ghostty_show_overlay: app focus set true");
        }
    }
    let entry = gs
        .surfaces
        .get_mut(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    entry.overlay.set_visible(visible);
    if visible {
        let focused = entry.overlay.focus();
        debug_log(&format!(
            "ghostty_show_overlay: makeFirstResponder result={}",
            focused
        ));
        entry.surface.set_focus(true);
    } else {
        entry.surface.set_focus(false);
    }
    Ok(())
}

/// Focus the native overlay so it receives keyboard input.
#[tauri::command]
pub fn ghostty_focus_overlay(
    surface_id: String,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
    let entry = gs
        .surfaces
        .get(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    if let Some(app) = gs.app.as_ref() {
        app.set_focus(true);
        debug_log("ghostty_focus_overlay: app focus set true");
    }
    let focused = entry.overlay.focus();
    debug_log(&format!(
        "ghostty_focus_overlay: makeFirstResponder result={}",
        focused
    ));
    entry.surface.set_focus(true);
    Ok(())
}

/// Send text to the terminal surface (for agent prompt injection).
#[tauri::command]
pub fn ghostty_send_text(
    surface_id: String,
    text: String,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let gs = state.lock().map_err(|_| "State lock error".to_string())?;
    let entry = gs
        .surfaces
        .get(&surface_id)
        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;

    entry.surface.send_text(&text);
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::resolve_surface_command;

    #[test]
    fn resolves_embedded_agent_command_names() {
        assert_eq!(resolve_surface_command(Some("claude-code")), Some("claude"));
        assert_eq!(resolve_surface_command(Some("codex")), Some("codex"));
        assert_eq!(resolve_surface_command(Some("terminal")), None);
        assert_eq!(resolve_surface_command(None), None);
    }
}

