/// Switch from one surface to another in a single IPC call.
/// Hides the old surface, repositions + shows + focuses the new one.
#[tauri::command]
pub fn ghostty_switch_surface(
    hide_surface_id: Option<String>,
    show_surface_id: String,
    x: f64,
    y: f64,
    width: f64,
    height: f64,
    state: State<'_, Mutex<super::GhosttyState>>,
) -> Result<(), String> {
    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;

    // Hide the old surface
    if let Some(ref hide_id) = hide_surface_id {
        if let Some(entry) = gs.surfaces.get_mut(hide_id) {
            entry.overlay.set_visible(false);
            entry.surface.set_focus(false);
        }
    }

    // Set app focus
    if let Some(app) = gs.app.as_ref() {
        app.set_focus(true);
    }

    // Position, show, and focus the new surface
    let entry = gs
        .surfaces
        .get_mut(&show_surface_id)
        .ok_or_else(|| format!("Surface not found: {}", show_surface_id))?;

    entry.overlay.update_frame(x, y, width, height);
    let scale = 2.0; // TODO: get actual scale factor
    entry
        .surface
        .set_size((width * scale) as u32, (height * scale) as u32);
    entry.overlay.set_visible(true);
    entry.overlay.focus();
    entry.surface.set_focus(true);

    Ok(())
}

