import { useEffect, useRef, useCallback } from "react";
import { invoke } from "@tauri-apps/api/core";

interface GhosttyTerminalProps {
  surfaceId: string | null;
  className?: string;
}

/**
 * Transparent placeholder that positions a native NSView overlay for libghostty.
 *
 * The actual terminal rendering happens in Metal via libghostty — this div
 * just tracks its position/size in the viewport and syncs it to the native layer.
 */
export function GhosttyTerminal({ surfaceId, className }: GhosttyTerminalProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const rafRef = useRef<number>(0);
  const prevSurfaceIdRef = useRef<string | null>(null);

  // Sync the native overlay position to match this div's position in the viewport
  const syncOverlay = useCallback(() => {
    if (!surfaceId || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    invoke("ghostty_update_overlay", {
      surfaceId,
      x: rect.x,
      y: rect.y,
      width: rect.width,
      height: rect.height,
    }).catch(console.error);
  }, [surfaceId]);

  useEffect(() => {
    if (!containerRef.current || !surfaceId) return;

    const rect = containerRef.current.getBoundingClientRect();
    const prevId = prevSurfaceIdRef.current;
    prevSurfaceIdRef.current = surfaceId;

    // Single IPC call: hide old surface + position/show/focus new surface
    invoke("ghostty_switch_surface", {
      hideSurfaceId: prevId,
      showSurfaceId: surfaceId,
      x: rect.x,
      y: rect.y,
      width: rect.width,
      height: rect.height,
    }).catch(console.error);

    // Track resize/reposition
    const observer = new ResizeObserver(() => {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = requestAnimationFrame(syncOverlay);
    });
    observer.observe(containerRef.current);

    // Also sync on scroll (in case the terminal is inside a scrollable container)
    const onScroll = () => {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = requestAnimationFrame(syncOverlay);
    };
    window.addEventListener("scroll", onScroll, true);

    return () => {
      observer.disconnect();
      window.removeEventListener("scroll", onScroll, true);
      cancelAnimationFrame(rafRef.current);

      // Hide overlay when component unmounts (no switch happening)
      invoke("ghostty_show_overlay", { surfaceId, visible: false }).catch(
        console.error
      );
    };
  }, [surfaceId, syncOverlay]);

  // Click to focus the native terminal
  const handleClick = useCallback(() => {
    if (surfaceId) {
      invoke("ghostty_focus_overlay", { surfaceId }).catch(console.error);
    }
  }, [surfaceId]);

  return (
    <div
      ref={containerRef}
      onClick={handleClick}
      className={`h-full w-full ${className ?? ""}`}
      style={{
        // Transparent so the native Metal view shows through
        background: "transparent",
        // Prevent the webview from capturing events meant for the native overlay
        pointerEvents: surfaceId ? "none" : "auto",
      }}
    >
      {!surfaceId && <div className="h-full w-full" />}
    </div>
  );
}

